import sailpoint.api.SailPointContext;
  import sailpoint.object.Application;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningPlan.Operation;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Util;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;


  // Logic starts from here
  Log logger = LogFactory.getLog("Ascension-Rule-BeforeProvisioning-EscapeSpeicalChar");
  logger.debug("Entering Ascension-Rule-BeforeProvisioning-EscapeSpeicalChar");

  if (plan != null) {
    if (plan.getAccountRequests() != null && !Util.isEmpty( plan.getAccountRequests(application.getName())) ) {
      for (AccountRequest accReq : plan.getAccountRequests(application.getName())) {
        if ( !Util.isEmpty( accReq.getAttributeRequests())  ){

          for(AttributeRequest attReq : accReq.getAttributeRequests()){
            Object val = attReq.getValue();
           
            if(val instanceof String){
              // replace "
              if( ((String) val).contains("\"")){
               
                val = (((String) val).replaceAll("\"", "\\\\\\\\\""));
              }
              attReq.setValue(val);
            }else if(val instanceof List){
              List newVal = new ArrayList();
              for(Object str : ((List)val)){
                // replace "
                if( ((String) str).contains("\"")){
                  
                  str = (((String) str).replaceAll("\"", "\\\\\\\\\""));
                }

                newVal.add(str);
              }
              attReq.setValue(newVal);
            }
          }
        }
      }
    }
  }
 

  logger.debug("Exiting Ascension-Rule-BeforeProvisioning-EscapeSpeicalChar");
